package com.trademaster.ims.mobile.support.model;
import jakarta.persistence.*;import java.time.Instant;
@Entity @Table(name="customer_support_messages",indexes=@Index(name="idx_support_message_ticket",columnList="ticket_id,created_at"))
public class SupportMessage{public enum SenderType{CUSTOMER,ADMIN,SYSTEM}@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="ticket_id",nullable=false)private Long ticketId;@Enumerated(EnumType.STRING)@Column(name="sender_type",nullable=false,length=20)private SenderType senderType=SenderType.CUSTOMER;@Column(nullable=false,length=1500)private String message;@Column(name="customer_visible",nullable=false)private boolean customerVisible=true;@Column(name="created_at",nullable=false,updatable=false)private Instant createdAt;@PrePersist void c(){createdAt=Instant.now();}public Long getId(){return id;}public Long getTicketId(){return ticketId;}public void setTicketId(Long v){ticketId=v;}public SenderType getSenderType(){return senderType;}public void setSenderType(SenderType v){senderType=v;}public String getMessage(){return message;}public void setMessage(String v){message=v;}public boolean isCustomerVisible(){return customerVisible;}public void setCustomerVisible(boolean v){customerVisible=v;}public Instant getCreatedAt(){return createdAt;}}